     setElements(prev => [...prev, elementWithId]);
  }, [setElements]);

  const addNote = useCallback((position?: Point) => {
    addElement({
      type: 'note',
      position: position || getTargetPosition(),
      width: 150,
      height: 100,
      rotation: 0,
      content: 'New Note',
