  };

  const downloadGeneratedImage = (imageUrl: string) => {
      if (!imageUrl) return;
      const link = document.createElement('a');
      link.href = imageUrl;
      link.download = `generated-canvas-image-${Date.now()}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  const addGeneratedImageToCanvas = useCallback((imageUrl: string) => {
    if (!imageUrl) return;

    const src = imageUrl;
    const img = new Image();
    img.onload = () => {
      const MAX_DIMENSION = 400;
      let { width, height } = img;
      if (width > MAX_DIMENSION || height > MAX_DIMENSION) {
        if (width > height) {
          height = (height / width) * MAX_DIMENSION;
          width = MAX_DIMENSION;
        } else {
          width = (width / height) * MAX_DIMENSION;
          height = MAX_DIMENSION;
        }
      }
      addElement({
        type: 'image',
        position: getTargetPosition(),
        src,
        width,
        height,
        rotation: 0,
      });
    };
    img.src = src;
  }, [addElement, getTargetPosition]);

  const downloadImage = useCallback((elementId: string) => {
    if (!elementId) return;
    const element = elements.find(el => el.id === elementId);
    if (element && (element.type === 'image' || element.type === 'drawing') && element.src) {
        const link = document.createElement('a');
        link.href = element.src;
        const mimeType = element.src.match(/data:(.*);base64/)?.[1] || 'image/png';
        const extension = mimeType.split('/')[1] || 'png';
        link.download = `canvas-image-${Date.now()}.${extension}`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    }
  }, [elements]);

  const handleContextMenu = useCallback((e: React.MouseEvent | React.TouchEvent, worldPoint: Point, elementId: string | null) => {
      e.preventDefault();

      const point = 'touches' in e ? e.touches[0] : e;
      if (!point) return;

      if (elementId && !selectedElementIds.includes(elementId)) {
        handleSelectElement(elementId, false);
      }
      setContextMenu({ x: point.clientX, y: point.clientY, worldPoint, elementId });

  }, [selectedElementIds, handleSelectElement]);

  const handleExportCanvas = () => {
    const elementsWithAnalysis = elements.map(el => {
        const analysis = analysisResults[el.id];
        if (analysis) {
            return { ...el, analysis };
        }
        return el;
    });

    const dataStr = JSON.stringify(elementsWithAnalysis, null, 2);
    const dataBlob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(dataBlob);
    const link = document.createElement('a');
    link.download = `infinite-canvas-export-${new Date().toISOString().split('T')[0]}.json`;
    link.href = url;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleImportCanvas = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
        try {
            const result = e.target?.result;
            if (typeof result !== 'string') throw new Error("File could not be read.");
            const data = JSON.parse(result);

            let finalElements: CanvasElement[] = [];
            let finalAnalysisResults: Record<string, AnalysisResult> = {};

            if (Array.isArray(data)) {
                data.forEach((item: any) => {
                    if (item && typeof item === 'object' && item.id) {
                        const { analysis, ...elementData } = item;
                        finalElements.push(elementData as CanvasElement);
                        if (analysis) finalAnalysisResults[item.id] = analysis;
                    }
                });
            } else if (data && typeof data === 'object' && Array.isArray(data.elements)) {
                finalElements = data.elements;
                finalAnalysisResults = data.analysisResults || {};
            } else {
                throw new Error("Invalid file format.");
            }

            setElements(finalElements);
            setAnalysisResults(finalAnalysisResults);
            setAnalysisVisibility({});

            const maxZ = Math.max(0, ...finalElements.map(el => el.zIndex || 0));
            zIndexCounter.current = maxZ + 1;
        } catch (error) {
            console.error("Error importing canvas:", error);
            alert(`Import failed: ${error instanceof Error ? error.message : 'Unknown error'}`);
        }
    };
    reader.readAsText(file);
    if (event.target) event.target.value = "";
  };

  const duplicateElement = useCallback((elementId: string) => {
    const elementToDuplicate = elements.find(el => el.id === elementId);
    if (!elementToDuplicate) return;

    const commonProperties = {
        position: {
            x: elementToDuplicate.position.x + 20,
            y: elementToDuplicate.position.y + 20,
        },
        width: elementToDuplicate.width,
        height: elementToDuplicate.height,
        rotation: elementToDuplicate.rotation,
    };

    let newElement: Omit<NoteElement, 'id' | 'zIndex'> | Omit<ImageElement, 'id' | 'zIndex'> | Omit<DrawingElement, 'id' | 'zIndex'> | Omit<ArrowElement, 'id' | 'zIndex'>;

    switch (elementToDuplicate.type) {
        case 'note':
            newElement = { ...commonProperties, type: 'note', content: elementToDuplicate.content, color: elementToDuplicate.color, textAlign: elementToDuplicate.textAlign };
            break;
        case 'image':
            newElement = { ...commonProperties, type: 'image', src: elementToDuplicate.src };
            break;
        case 'drawing':
            newElement = { ...commonProperties, type: 'drawing', src: elementToDuplicate.src };
            break;
        case 'arrow':
            newElement = { ...commonProperties, type: 'arrow', start: { x: elementToDuplicate.start.x + 20, y: elementToDuplicate.start.y + 20 }, end: { x: elementToDuplicate.end.x + 20, y: elementToDuplicate.end.y + 20 }, color: elementToDuplicate.color };
            break;
        default:
            return;
    }
    addElement(newElement);
  }, [elements, addElement]);

  useEffect(() => {
    const handlePaste = async (event: ClipboardEvent) => {
        const target = event.target as HTMLElement;
        const isEditingText = target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.isContentEditable;
        if(isEditingText) return;

        event.preventDefault();
        const items = event.clipboardData?.items;
        if (!items) return;

        const position = getTargetPosition();
        const imageItem = Array.from(items).find(item => item.type.startsWith('image/'));
        if (imageItem) {
            const file = imageItem.getAsFile();
            if (file) addImagesToCanvas([file], position);
            return;
        }

        const textItem = Array.from(items).find(item => item.type === 'text/plain');
        if (textItem) {
            textItem.getAsString(text => {
                 addElement({ type: 'note', position, width: 200, height: 150, rotation: 0, content: text, color: COLORS[Math.floor(Math.random() * COLORS.length)].bg });
            });
        }
    };

    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, [addElement, addImagesToCanvas, getTargetPosition]);

    const handleAnalyzeElement = useCallback(async (elementId: string) => {
        const genAI = getAi();
        if (!genAI) return;

        const element = elements.find(el => el.id === elementId);
        if (!element || (element.type !== 'image' && element.type !== 'drawing') || !element.src) return;

        setAnalyzingElementId(elementId);
        try {
            const [header, data] = element.src.split(',');
            const mimeType = header.match(/data:(.*);base64/)?.[1] || 'image/png';
            const imagePart = { inlineData: { data, mimeType } };

            const response = await genAI.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: { 
                    parts: [
                        imagePart,
                        { text: "Analyze this image. Provide a detailed description and 2-3 creative style or composition suggestions to help optimize a prompt for image generation." }
                    ] 
                },
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            description: { type: Type.STRING },
                            suggestions: { type: Type.ARRAY, items: { type: Type.STRING } }
                        }
                    }
                }
            });

            const resultJson = JSON.parse(response.text);
            setAnalysisResults(prev => ({ ...prev, [elementId]: { en: { description: resultJson.description, suggestions: resultJson.suggestions } } }));
            setAnalysisVisibility(prev => ({ ...prev, [elementId]: true }));
        } catch (error) {
            console.error("Analysis Error:", error);
        } finally {
            setAnalyzingElementId(null);
        }
    }, [getAi, elements]);

    const handleOptimizeNotePrompt = useCallback(async (elementId: string) => {
        const genAI = getAi();
        if (!genAI) return;
        const element = elements.find(el => el.id === elementId);
        if (!element || element.type !== 'note' || !element.content.trim()) return;
        setAnalyzingElementId(elementId);
        try {
            const response = await genAI.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: element.content,
                config: {
                    systemInstruction: `Optimize the prompt for image generation. Return JSON with 'description' and 'suggestions' array.`,
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            description: { type: Type.STRING },
                            suggestions: { type: Type.ARRAY, items: { type: Type.STRING } }
                        }
                    }
                }
            });
            const resultJson = JSON.parse(response.text);
            setAnalysisResults(prev => ({ ...prev, [elementId]: { en: resultJson } }));
            setAnalysisVisibility(prev => ({ ...prev, [elementId]: true }));
        } catch (error) {
            console.error("Optimization Error:", error);
        } finally {
            setAnalyzingElementId(null);
        }
    }, [getAi, elements]);

    const handleToggleAnalysisVisibility = useCallback((elementId: string) => {
        setAnalysisVisibility(prev => ({ ...prev, [elementId]: !prev[elementId] }));
      }, []);

      const handleClearAnalysis = useCallback((elementId: string) => {
        setAnalysisResults(prev => { const next = { ...prev }; delete next[elementId]; return next; });
        setAnalysisVisibility(prev => { const next = { ...prev }; delete next[elementId]; return next; });
      }, []);

    const handleTranslateAnalysis = useCallback(async (elementId: string) => {
        const genAI = getAi();
        if (!genAI) return;
        const analysis = analysisResults[elementId];
        if (!analysis || analysis.zh) return;
        setTranslatingElementId(elementId);
        try {
            const prompt = `Translate this JSON object values to Traditional Chinese. Keep structure:\n\n${JSON.stringify(analysis.en)}`;
            const response = await genAI.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            description: { type: Type.STRING },
                            suggestions: { type: Type.ARRAY, items: { type: Type.STRING } }
                        }
                    }
                }
            });
            setAnalysisResults(prev => ({ ...prev, [elementId]: { ...prev[elementId], zh: JSON.parse(response.text) } }));
        } catch (error) {
            console.error("Translation Error:", error);
        } finally {
            setTranslatingElementId(null);
        }
    }, [getAi, analysisResults]);


  const contextMenuElement = contextMenu?.elementId ? elements.find(el => el.id === contextMenu.elementId) : null;

  return (
    <main className="relative w-screen h-screen bg-gray-100 font-sans" onClick={() => setContextMenu(null)}>
      <div 
        className={`absolute top-4 z-20 p-4 bg-white/90 backdrop-blur-md rounded-xl shadow-2xl border border-gray-200 w-72 flex flex-col gap-4 transition-all duration-300 ease-in-out ${isMenuCollapsed ? (panelAlignment === 'left' ? '-translate-x-full' : 'translate-x-full') : 'translate-x-0'} ${panelAlignment === 'left' ? 'left-4' : 'right-4'}`}
      >
        <div className="flex justify-between items-start">
          <div>
            <h1 className="text-xl font-black text-blue-600 flex items-center gap-1">
                <span className="text-2xl">🍌</span> {t('infiniteCanvas')}
            </h1>
            <p className="text-[10px] text-blue-500 uppercase tracking-widest font-black">Ver 3.0.0.1 Flash <span className="text-gray-300">| Gemini 3</span></p>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-2">
            <button onClick={() => addNote()} className="px-3 py-2.5 text-xs font-bold bg-blue-600 text-white rounded-lg hover:bg-blue-700 shadow-sm transition-all flex flex-col items-center gap-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                {t('addNote')}
            </button>
            <button onClick={() => addArrow()} className="px-3 py-2.5 text-xs font-bold bg-green-600 text-white rounded-lg hover:bg-green-700 shadow-sm transition-all flex flex-col items-center gap-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 8l4 4m0 0l-4 4m4-4H3"/></svg>
                {t('addArrow')}
            </button>
            <button onClick={() => addDrawing()} className="px-3 py-2.5 text-xs font-bold bg-purple-600 text-white rounded-lg hover:bg-purple-700 shadow-sm transition-all flex flex-col items-center gap-1 col-span-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"/></svg>
                {t('addDrawing')}
            </button>
            <label className="cursor-pointer px-3 py-2.5 text-xs font-bold bg-orange-500 text-white rounded-lg hover:bg-orange-600 shadow-sm transition-all flex flex-col items-center gap-1 col-span-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"/></svg>
                {t('addImages')}
                <input type="file" accept="image/*" ref={imageInputRef} className="hidden" onChange={handleImageUpload} multiple />
            </label>
        </div>

        {showImageEditInMenu && (
            <div className="border-t border-gray-100 pt-3 flex flex-col gap-2">
                <h2 className="text-[10px] font-black text-gray-400 uppercase tracking-wider">{t('imageEdit')}</h2>
                <div className="grid grid-cols-2 gap-2">
                    <button onClick={() => handleStartImageEdit(selectedElementIds[0])} className="px-2 py-2 text-[11px] font-bold bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all">{t('removeOrEditObject')}</button>
                    <button onClick={() => handleStartOutpainting(selectedElementIds[0])} className="px-2 py-2 text-[11px] font-bold bg-teal-600 text-white rounded-lg hover:bg-teal-700 transition-all">{t('expandImage')}</button>
                </div>
            </div>
        )}

        {selectedElementIds.length > 0 && canChangeColor && (
            <div className="border-t border-gray-100 pt-3">
                <h2 className="text-[10px] font-black text-gray-400 uppercase tracking-wider mb-2">{t('color')}</h2>
                <div className="grid grid-cols-8 gap-1">
                    {COLORS.map(color => (
                        <button key={color.name} onClick={() => handleColorChange(color.bg)} className={`w-6 h-6 rounded-md border border-black/5 ${color.bg} hover:scale-110 transition-transform`}/>
                    ))}
                </div>
            </div>
        )}

         <div className="flex flex-col gap-2 border-t border-gray-100 pt-3">
            <h2 className="text-[10px] font-black text-gray-400 uppercase tracking-wider">{t('settings')}</h2>
             <div className="grid grid-cols-2 gap-2">
                <button onClick={toggleLanguage} className="px-2 py-2 text-xs font-bold bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-all">{t('changeLanguage')}</button>
                <button onClick={() => setPanelAlignment(p => p === 'left' ? 'right' : 'left')} className="px-2 py-2 text-xs font-bold bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-all">
                    {panelAlignment === 'left' ? '👉' : '👈'} {panelAlignment === 'left' ? t('alignPanelRight') : t('alignPanelLeft')}
                </button>
             </div>
         </div>

         <div className="flex flex-col gap-2 border-t border-gray-100 pt-3">
            <h2 className="text-[10px] font-black text-gray-400 uppercase tracking-wider">{t('controls')}</h2>
            <div className="mb-1">
                <div className="w-full bg-gray-100 rounded-lg p-1 grid grid-cols-2 gap-1">
                    <button onClick={() => setInteractionMode('pan')} className={`px-2 py-1.5 text-xs font-bold rounded-md transition-all ${interactionMode === 'pan' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>{t('panMode')}</button>
                    <button onClick={() => setInteractionMode('select')} className={`px-2 py-1.5 text-xs font-bold rounded-md transition-all ${interactionMode === 'select' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>{t('selectMode')}</button>
                </div>
            </div>
            <div className="grid grid-cols-2 gap-2">
                <button onClick={handleExportCanvas} className="px-2 py-2 text-xs font-bold bg-blue-50 text-blue-700 rounded-lg hover:bg-blue-100 transition-all">{t('export')}</button>
                <label className="cursor-pointer text-center px-2 py-2 text-xs font-bold bg-blue-50 text-blue-700 rounded-lg hover:bg-blue-100 transition-all">
                    {t('import')}
                    <input type="file" accept=".json" ref={importInputRef} className="hidden" onChange={handleImportCanvas} />
                </label>
                <button onClick={undo} disabled={!canUndo} className="px-2 py-2 text-xs font-bold bg-gray-100 text-gray-600 rounded-lg hover:bg-gray-200 disabled:opacity-30 transition-all">{t('undo')}</button>
                <button onClick={redo} disabled={!canRedo} className="px-2 py-2 text-xs font-bold bg-gray-100 text-gray-600 rounded-lg hover:bg-gray-200 disabled:opacity-30 transition-all">{t('redo')}</button>
                <button onClick={groupElements} disabled={!getSelectedGroupInfo.canGroup} className="px-2 py-2 text-xs font-bold bg-indigo-50 text-indigo-700 rounded-lg hover:bg-indigo-100 disabled:opacity-30 transition-all flex items-center justify-center gap-1">
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6zM4 16a2 2 0 012-2h2a2 2 0 01-2 2H6a2 2 0 01-2-2v-2zM14 16a2 2 0 012-2h2a2 2 0 01-2 2h-2a2 2 0 01-2-2v-2z"/></svg>
                    {t('group')}
                </button>
                <button onClick={ungroupElements} disabled={!getSelectedGroupInfo.canUngroup} className="px-2 py-2 text-xs font-bold bg-indigo-50 text-indigo-700 rounded-lg hover:bg-indigo-100 disabled:opacity-30 transition-all flex items-center justify-center gap-1">
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10"/></svg>
                    {t('ungroup')}
                </button>
                <button onClick={bringToFront} disabled={selectedElementIds.length === 0} className="px-2 py-2 text-[10px] font-bold bg-gray-800 text-white rounded-lg hover:bg-black disabled:opacity-30 transition-all truncate">{t('bringToFront')}</button>
                <button onClick={sendToBack} disabled={selectedElementIds.length === 0} className="px-2 py-2 text-[10px] font-bold bg-gray-500 text-white rounded-lg hover:bg-gray-600 disabled:opacity-30 transition-all truncate">{t('sendToBack')}</button>
                <button onClick={deleteElement} disabled={selectedElementIds.length === 0} className="px-2 py-2 text-xs font-bold bg-red-50 text-red-600 rounded-lg hover:bg-red-100 disabled:opacity-30 transition-all col-span-1">{t('delete')}</button>
                <button onClick={resetView} className="px-2 py-2 text-xs font-bold bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-all col-span-1">{t('resetView')}</button>
            </div>
        </div>
      </div>

      <button
        onClick={() => setIsMenuCollapsed(!isMenuCollapsed)}
        className="absolute top-4 z-20 p-2.5 bg-white/90 backdrop-blur-md rounded-full shadow-xl border border-gray-200 hover:bg-gray-100 transition-all duration-300 ease-in-out"
        style={{ [panelAlignment]: isMenuCollapsed ? '1rem' : 'calc(1rem + 18rem + 0.5rem)' }}
      >
        <svg xmlns="http://www.w3.org/2000/svg" className={`h-5 w-5 text-gray-700 transition-transform ${isMenuCollapsed ? (panelAlignment === 'left' ? 'rotate-180' : '') : (panelAlignment === 'left' ? '' : 'rotate-180')}`} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7" />
        </svg>
      </button>

      <InfiniteCanvas 
        ref={canvasApiRef}
        elements={elements} 
        selectedElementIds={selectedElementIds}
        onSelectElement={handleSelectElement}
        onMarqueeSelect={handleMarqueeSelect}
        onUpdateElement={updateElements}
        onUpdateMultipleElements={updateMultipleElements}
        onInteractionEnd={handleInteractionEnd}
        setResetViewCallback={getResetViewCallback} 
        onGenerate={handleGenerate}
        onContextMenu={handleContextMenu}
        onEditDrawing={handleEditDrawing}
        onMouseMove={handleCanvasMouseMove}
        onViewportChange={handleViewportChange}
        imageStyle={imageStyle}
        onSetImageStyle={setImageStyle}
        imageAspectRatio={imageAspectRatio}
        onSetImageAspectRatio={setImageAspectRatio}
        outpaintingState={outpaintingState}
        onUpdateOutpaintingFrame={handleUpdateOutpaintingFrame}
        onCancelOutpainting={handleCancelOutpainting}
        onOutpaintingGenerate={handleOutpaintingGenerate}
        onAutoPromptGenerate={handleAutoPromptGenerate}
        interactionMode={interactionMode}
        t={t}
        language={language}
        analysisResults={analysisResults}
        analyzingElementId={analyzingElementId}
        onAnalyzeElement={handleAnalyzeElement}
        onOptimizeNotePrompt={handleOptimizeNotePrompt}
        analysisVisibility={analysisVisibility}
        onToggleAnalysisVisibility={handleToggleAnalysisVisibility}
        onClearAnalysis={handleClearAnalysis}
        onTranslateAnalysis={handleTranslateAnalysis}
        translatingElementId={translatingElementId}
      />

      <Minimap elements={elements} viewport={viewport} onPanTo={handlePanTo} onZoomIn={handleZoomIn} onZoomOut={handleZoomOut} />

      {isGenerating && (
        <div className="absolute inset-0 z-50 bg-black/60 backdrop-blur-sm flex flex-col items-center justify-center text-white">
            <div className="relative">
                <div className="w-16 h-16 border-4 border-blue-400/20 border-t-blue-500 rounded-full animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center text-2xl">🍌</div>
            </div>
            <p className="mt-6 text-xl font-black tracking-widest uppercase">{t('generatingImages')}</p>
            <p className="text-blue-300 animate-pulse">{t('thisMayTakeAMoment')}</p>
        </div>
      )}

      {generatedImages && generatedImages.length > 0 && (
        <div className="absolute inset-0 z-50 bg-black/80 backdrop-blur-md flex items-center justify-center p-4" onClick={() => setGeneratedImages(null)}>
          <div className="bg-white rounded-3xl shadow-2xl p-6 max-w-5xl w-full max-h-[90vh] flex flex-col overflow-hidden" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-black text-gray-800">{t('chooseAnImage')}</h2>
              <button onClick={() => setGeneratedImages(null)} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
