const handlePasteFromClipboard = useCallback(async () => {
  // 內部輔助函式：處理文字內容 (JSON 畫布物件 或 純文字便利貼)
  const processTextContent = (text: string) => {
      try {
          // 嘗試解析為 JSON 畫布物件
          const data = JSON.parse(text);
          const items = Array.isArray(data) ? data : [data];
          const validItems = items.filter((i: any) => i.type && i.position);

          if (validItems.length > 0) {
              const targetPos = getTargetPosition();
              const minX = Math.min(...validItems.map((i: any) => i.position.x));
              const minY = Math.min(...validItems.map((i: any) => i.position.y));

              const newElements = validItems.map((item: any) => ({
                  ...item,
                  id: `${Date.now()}-${Math.random().toString(36).substring(2, 9)}`,
                  zIndex: zIndexCounter.current++,
                  position: {
                      x: item.position.x - minX + targetPos.x,
                      y: item.position.y - minY + targetPos.y
                  }
              }));

              setElements(prev => [...prev, ...newElements]);
              setSelectedElementIds(newElements.map((el: any) => el.id));
              return true; // 成功處理 JSON
          }
      } catch (e) {
          // 解析失敗，視為普通文字
      }

      // 如果不是 JSON，則建立純文字便利貼
      const position = getTargetPosition();
      addElement({
          type: 'note',
          position,
          width: 200,
          height: 150,
          rotation: 0,
          content: text,
          color: COLORS[Math.floor(Math.random() * COLORS.length)].bg,
      });
      return true; // 成功處理純文字
  };

  try {
      // 1. 優先使用 read() API，這是一次性請求，可以同時看到圖片和文字類型
      // 這樣可以避免先調用 readText() 失敗後再調用 read() 導致的瀏覽器權限提示衝突
      const clipboardItems = await navigator.clipboard.read();

      for (const item of clipboardItems) {
          // A. 優先檢查是否有圖片 (image/*)
          // 這是為了解決 "作業系統剪貼簿中的圖片" 導致重複按鈕的問題
          const imageType = item.types.find(type => type.startsWith('image/'));
          if (imageType) {
              const blob = await item.getType(imageType);
              const reader = new FileReader();
              reader.onload = (e) => {
                  const src = e.target?.result as string;
                  if (src) {
                      const img = new Image();
                      img.onload = () => {
                          const MAX_DIMENSION = 300;
                          let { width, height } = img;
                          if (width > MAX_DIMENSION || height > MAX_DIMENSION) {
                              if (width > height) {
                                  height = (height / width) * MAX_DIMENSION;
                                  width = MAX_DIMENSION;
                              } else {
                                  width = (width / height) * MAX_DIMENSION;
                                  height = MAX_DIMENSION;
                              }
                          }
                          addElement({
                              type: 'image',
                              position: getTargetPosition(),
                              src,
                              width,
                              height,
                              rotation: 0,
                          });
                      };
                      img.src = src;
                  }
              };
              reader.readAsDataURL(blob);
              return; // 找到圖片後直接結束，不再處理文字
          }

          // B. 如果沒有圖片，檢查是否有純文字 (text/plain)
          if (item.types.includes('text/plain')) {
              const blob = await item.getType('text/plain');
              const text = await blob.text();
              if (text && processTextContent(text)) return;
          }
      }
  } catch (err) {
      // 2. 如果 read() 失敗 (例如 Firefox 預設不開放 read() 讀取文字，或使用者拒絕權限)
      // 退回使用相容性最好的 readText()
      try {
          const text = await navigator.clipboard.readText();
          if (text) {
              processTextContent(text);
          }
      } catch (textErr) {
          console.error("Paste failed:", textErr);
      }
  }
}, [addElement, getTargetPosition, setElements]);

