                                src,
                                width,
                                height,
                                rotation: 0,
                                zIndex: zIndexCounter.current++,
                                id: Math.random().toString(36).substr(2, 9),
                            });
                        };
                        img.src = src;
                    }
                };
                reader.readAsDataURL(blob);
                return; // 找到圖片後直接結束，不再處理文字
            }

            // B. 如果沒有圖片，檢查是否有純文字 (text/plain)
            if (item.types.includes('text/plain')) {
                const blob = await item.getType('text/plain');
                const text = await blob.text();
                if (text && processTextContent(text)) return;
            }
        }
    } catch (err) {
        // 2. 如果 read() 失敗 (例如 Firefox 預設不開放 read() 讀取文字，或使用者拒絕權限)
        // 退回使用相容性最好的 readText()
        try {
            const text = await navigator.clipboard.readText();
            if (text) {
                processTextContent(text);
            }
        } catch (textErr) {
            console.error("Paste failed:", textErr);
        }
    }
  }, [addElement, getTargetPosition, setElements]);

  useEffect(() => {
      const handleKeyDown = (e: KeyboardEvent) => {
          if ((e.ctrlKey || e.metaKey) && e.key === 'v') {
              handlePasteFromClipboard();
          }
      }
      window.addEventListener('keydown', handleKeyDown);
      return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handlePasteFromClipboard]);


  const onUpdateElement = useCallback((updatedElement: CanvasElement, dragDelta?: Point) => {
    setElements(prev => prev.map(el => el.id === updatedElement.id ? updatedElement : el));
  }, []);

  const onUpdateMultipleElements = useCallback((updates: (Partial<CanvasElement> & { id: string })[]) => {
      setElements(prev => prev.map(el => {
          const update = updates.find(u => u.id === el.id);
          return update ? { ...el, ...update } : el;
      }));
  }, []);

  const actions = {
      addNote: (pos: Point) => addElement({ type: 'note', position: pos, content: '', color: COLORS[0].bg, width: 200, height: 150, rotation: 0, zIndex: 0, id: '' }),
      addArrow: (pos: Point) => addElement({ type: 'arrow', position: pos, start: {x: pos.x-50, y:pos.y}, end: {x: pos.x+50, y:pos.y}, color: 'black', width: 100, height: 20, rotation: 0, zIndex: 0, id: '' }),
      addDrawing: (pos: Point) => addElement({ type: 'drawing', position: pos, src: '', width: 200, height: 200, rotation: 0, zIndex: 0, id: '' }),
      addImage: (pos: Point) => {
          const input = document.createElement('input');
          input.type = 'file';
          input.accept = 'image/*';
          input.onchange = (e) => {
              const file = (e.target as HTMLInputElement).files?.[0];
              if (file) {
                  const reader = new FileReader();
                  reader.onload = (event) => {
                      const src = event.target?.result as string;
                      const img = new Image();
                      img.onload = () => {
                          addElement({ type: 'image', position: pos, src, width: img.width/2, height: img.height/2, rotation: 0, zIndex: 0, id: '' });
                      }
                      img.src = src;
                  }
                  reader.readAsDataURL(file);
              }
          }
          input.click();
      },
      editDrawing: (id: string) => setDrawingElementId(id),
      startImageEdit: (id: string) => setEditingImageId(id),
      startOutpainting: (id: string) => {
           const el = elements.find(e => e.id === id) as ImageElement;
           if(el) setOutpaintingState({ element: el, frame: { position: el.position, width: el.width, height: el.height }})
      },
      deleteElement: () => {
          setElements(prev => prev.filter(el => !selectedElementIds.includes(el.id) && el.id !== contextMenu?.elementId));
          setSelectedElementIds([]);
      },
      bringToFront: () => {
         if(contextMenu?.elementId) {
             setElements(prev => {
                const newElements = [...prev];
                const idx = newElements.findIndex(e => e.id === contextMenu.elementId);
                if(idx >= 0) {
                    const el = newElements[idx];
                    el.zIndex = Math.max(...newElements.map(e => e.zIndex)) + 1;
                    zIndexCounter.current = el.zIndex + 1;
                }
                return newElements;
             });
         }
      },
      sendToBack: () => {
         if(contextMenu?.elementId) {
             setElements(prev => {
                const newElements = [...prev];
                const idx = newElements.findIndex(e => e.id === contextMenu.elementId);
                if(idx >= 0) {
                    const el = newElements[idx];
                    el.zIndex = Math.min(...newElements.map(e => e.zIndex)) - 1;
                }
                return newElements;
             });
         }
      },
      changeColor: (color: string) => {
           setElements(prev => prev.map(el => {
               if(contextMenu?.elementId === el.id || selectedElementIds.includes(el.id)) {
                   if(el.type === 'note' || el.type === 'arrow') return { ...el, color };
               }
               return el;
           }));
      },
      downloadImage: (id: string) => {
          const el = elements.find(e => e.id === id);
          if (el && (el.type === 'image' || el.type === 'drawing')) {
              const a = document.createElement('a');
              a.href = el.src;
              a.download = `image-${id}.png`;
              a.click();
          }
      },
      duplicateElement: (id: string) => {
          const el = elements.find(e => e.id === id);
          if(el) addElement({ ...el, id: '', position: { x: el.position.x + 20, y: el.position.y + 20 } });
      },
      toggleLanguage: () => setLanguage(prev => prev === 'en' ? 'zh' : 'en'),
      groupElements: () => {},
      ungroupElements: () => {},
      copyToClipboard: (id: string) => {
          const el = elements.find(e => e.id === id);
          if (el && el.type === 'note') {
              navigator.clipboard.writeText(el.content);
          }
      }
  }

  return (
    <div className="w-screen h-screen overflow-hidden">
      <InfiniteCanvas
        ref={canvasRef}
        elements={elements}
        selectedElementIds={selectedElementIds}
        onSelectElement={(id, shift) => {
            if (id === null) {
                if(!shift) setSelectedElementIds([]);
            } else {
                setSelectedElementIds(prev => shift ? (prev.includes(id) ? prev.filter(pid => pid !== id) : [...prev, id]) : [id]);
            }
        }}
        onMarqueeSelect={(ids, shift) => setSelectedElementIds(prev => shift ? [...new Set([...prev, ...ids])] : ids)}
        onUpdateElement={onUpdateElement}
        onUpdateMultipleElements={onUpdateMultipleElements}
        onInteractionEnd={() => {}}
        setResetViewCallback={(cb) => resetViewCallbackRef.current = cb}
        onGenerate={() => {}}
        onContextMenu={(e, worldPoint, elementId) => {
            e.preventDefault();
            setContextMenu({ x: e.clientX, y: e.clientY, worldPoint, elementId });
        }}
        onEditDrawing={(id) => setDrawingElementId(id)}
        onMouseMove={() => {}}
        onViewportChange={setViewport}
        imageStyle={imageStyle}
        onSetImageStyle={setImageStyle}
        imageAspectRatio={imageAspectRatio}
        onSetImageAspectRatio={setImageAspectRatio}
        outpaintingState={outpaintingState}
        onUpdateOutpaintingFrame={(frame) => setOutpaintingState(prev => prev ? { ...prev, frame } : null)}
        onCancelOutpainting={() => setOutpaintingState(null)}
        onOutpaintingGenerate={() => {}}
        onAutoPromptGenerate={async () => ""}
        interactionMode={interactionMode}
        t={t}
        language={language}
        analysisResults={analysisResults}
        analyzingElementId={analyzingElementId}
        onAnalyzeElement={(id) => {}}
        onOptimizeNotePrompt={(id) => {}}
        analysisVisibility={analysisVisibility}
        onToggleAnalysisVisibility={(id) => setAnalysisVisibility(prev => ({...prev, [id]: !prev[id]}))}
        onClearAnalysis={(id) => {}}
        onTranslateAnalysis={(id) => {}}
        translatingElementId={translatingElementId}
      />

      {contextMenu && (
        <ContextMenu
            menuData={contextMenu}
            onClose={() => setContextMenu(null)}
            actions={actions}
            canChangeColor={true}
            canGroup={selectedElementIds.length > 1}
            canUngroup={false}
            elementType={contextMenu.elementId ? elements.find(e => e.id === contextMenu.elementId)?.type || null : null}
            t={t}
        />
      )}

      {drawingElementId && (
        <DrawingModal 
            element={elements.find(e => e.id === drawingElementId) as DrawingElement}
            onSave={(id, dataUrl) => {
                setElements(prev => prev.map(el => el.id === id ? { ...el, src: dataUrl } : el));
                setDrawingElementId(null);
            }}
            onClose={() => setDrawingElementId(null)}
            t={t}
        />
      )}

      {editingImageId && (
        <ImageEditModal
            element={elements.find(e => e.id === editingImageId) as ImageElement}
            onSave={(id, dataUrl) => {
                setElements(prev => prev.map(el => el.id === id ? { ...el, src: dataUrl } : el));
                setEditingImageId(null);
            }}
            onClose={() => setEditingImageId(null)}
            ai={ai}
            t={t}
        />
      )}

      <Minimap
        elements={elements}
        viewport={viewport}
        onPanTo={(pt) => canvasRef.current?.panTo(pt)}
        onZoomIn={() => canvasRef.current?.zoomIn()}
        onZoomOut={() => canvasRef.current?.zoomOut()}
      />
    </div>
  );
}

