            <div className="grid grid-cols-3 gap-1">
                <button onClick={() => alignElements('left')} className="p-2 bg-gray-50 rounded hover:bg-gray-100" title={t('alignLeft')}><svg className="w-4 h-4 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M4 19h2V5H4v14zm5-4h9v-2H9v2zm0-5h11V8H9v2z"/></svg></button>
                <button onClick={() => alignElements('center')} className="p-2 bg-gray-50 rounded hover:bg-gray-100" title={t('alignCenter')}><svg className="w-4 h-4 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M8 19h3v2h2v-2h3v-2h-3v-2h-2v2H8v2zm-2-7h12v-2H6v2zm3-5h6V5H9v2z"/></svg></button>
                <button onClick={() => alignElements('right')} className="p-2 bg-gray-50 rounded hover:bg-gray-100" title={t('alignRight')}><svg className="w-4 h-4 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M18 19h2V5h-2v14zM6 15h9v-2H6v2zm0-5h11V8H6v2z"/></svg></button>
                <button onClick={() => alignElements('top')} className="p-2 bg-gray-50 rounded hover:bg-gray-100" title={t('alignTop')}><svg className="w-4 h-4 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M5 4v2h14V4H5zm10 5v9h-2V9h2zm-5 0v11H8V9h2z"/></svg></button>
                <button onClick={() => alignElements('middle')} className="p-2 bg-gray-50 rounded hover:bg-gray-100" title={t('alignMiddle')}><svg className="w-4 h-4 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M19 8v3h2v2h-2v3h-2v-3h-2v-2h2V8h2zm-7-2v12h-2V6h2zm-5 3v6H5V9h2z"/></svg></button>
                <button onClick={() => alignElements('bottom')} className="p-2 bg-gray-50 rounded hover:bg-gray-100" title={t('alignBottom')}><svg className="w-4 h-4 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M5 18v2h14v-2H5zm10-5v-9h-2v9h2zm-5-0v-11H8v11h2z"/></svg></button>
                <button onClick={() => distributeElements('h')} className="p-2 bg-gray-50 rounded hover:bg-gray-100" title={t('distributeH')}><svg className="w-4 h-4 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M4 5v14h2V5H4zm14 0v14h2V5h-2zM8 8h8v2H8V8zm0 6h8v2H8v-2z"/></svg></button>
                <button onClick={() => distributeElements('v')} className="p-2 bg-gray-50 rounded hover:bg-gray-100" title={t('distributeV')}><svg className="w-4 h-4 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M5 4h14v2H5V4zm0 14h14v2H5v-2zM8 8v8h2V8H8zm6 0v8h2V8h-2z"/></svg></button>
