  } = useHistoryState<CanvasElement[]>(INITIAL_ELEMENTS);

  const [selectedElementIds, setSelectedElementIds] = useState<string[]>([]);
  const [resetView, setResetView] = useState<() => void>(() => () => {});
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedImages, setGeneratedImages] = useState<string[] | null>(null);
  const [contextMenu, setContextMenu] = useState<ContextMenuData | null>(null);
  const [editingDrawing, setEditingDrawing] = useState<DrawingElement | null>(null);
  const [editingImage, setEditingImage] = useState<ImageElement | null>(null);
  const [outpaintingState, setOutpaintingState] = useState<OutpaintingState | null>(null);
  const [imageStyle, setImageStyle] = useState<string>('Default');
  const [imageAspectRatio, setImageAspectRatio] = useState<string>('1:1');
  const [isMenuCollapsed, setIsMenuCollapsed] = useState(false);
  const [isDraggingOver, setIsDraggingOver] = useState(false);
  const [language, setLanguage] = useState<'en' | 'zh'>('zh');
  const [panelAlignment, setPanelAlignment] = useState<'left' | 'right'>('left');
  const [interactionMode, setInteractionMode] = useState<'pan' | 'select'>('pan');
  const [analysisResults, setAnalysisResults] = useState<Record<string, AnalysisResult>>({});
  const [analyzingElementId, setAnalyzingElementId] = useState<string | null>(null);
  const [analysisVisibility, setAnalysisVisibility] = useState<Record<string, boolean>>({});
  const [translatingElementId, setTranslatingElementId] = useState<string | null>(null);
  const [isSnapEnabled, setIsSnapEnabled] = useState(true);
  const [viewport, setViewport] = useState<ViewportData>({
    x: 0,
    y: 0,
    width: window.innerWidth,
    height: window.innerHeight,
    zoom: 1
  });

  const imageInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);
  const canvasApiRef = useRef<CanvasApi>(null);
  const lastImagePosition = useRef<Point | null>(null);
  const zIndexCounter = useRef(INITIAL_ELEMENTS.length + 10);
  const dragCounter = useRef(0);
  const lastWorldMousePosition = useRef<Point | null>(null);

  const ai = useRef<GoogleGenAI | null>(null);

  const t = useCallback((key: string) => {
    return translations[language][key] || key;
  }, [language]);

  const getAi = useCallback(() => {
    if (!ai.current) {
        if (!process.env.API_KEY) {
            alert("API_KEY environment variable is not set.");
            return null;
        }
        ai.current = new GoogleGenAI({ apiKey: process.env.API_KEY });
    }
    return ai.current;
  }, []);

  const getCenterOfViewport = useCallback((): Point => {
    if (canvasApiRef.current) {
        const screenCenter: Point = {
            x: window.innerWidth / 2,
            y: window.innerHeight / 2,
        };
        return canvasApiRef.current.screenToWorld(screenCenter);
    }
    return {x: 0, y: 0};
  }, []);

  const getTargetPosition = useCallback((): Point => {
    const selected = elements.filter(el => selectedElementIds.includes(el.id));
    if (selected.length > 0) {
        const minX = Math.min(...selected.map(el => el.position.x));
        const minY = Math.min(...selected.map(el => el.position.y));
        const maxY = Math.max(...selected.map(el => el.position.y));
        const maxX = Math.max(...selected.map(el => el.position.x + el.width));
        return { x: maxX + 100, y: (minY + maxY) / 2 };
    }
    return getCenterOfViewport();
  }, [elements, selectedElementIds, getCenterOfViewport]);

  const addElement = useCallback((newElement: any) => {
    const elementWithId: CanvasElement = {
        ...newElement,
        id: `${Date.now()}-${Math.random().toString(36).substring(2, 9)}`,
        zIndex: zIndexCounter.current++,
    } as CanvasElement;
     setElements(prev => [...prev, elementWithId]);
  }, [setElements]);

  const addNote = useCallback((position?: Point) => {
    addElement({
      type: 'note',
      position: position || getTargetPosition(),
      width: 200,
      height: 150,
      rotation: 0,
      content: 'New Note',
      color: COLORS[Math.floor(Math.random() * COLORS.length)].bg,
    });
  }, [addElement, getTargetPosition]);

  const addArrow = useCallback((position?: Point) => {
    const start = position || getTargetPosition();
    const end = { x: start.x + 150, y: start.y };
    addElement({
      type: 'arrow',
      start,
      end,
      position: { x: (start.x + end.x) / 2, y: (start.y + end.y) / 2 },
      width: 150,
      height: 30,
      rotation: 0,
      color: 'text-red-500',
    });
  }, [addElement, getTargetPosition]);

  const addDrawing = useCallback((position?: Point) => {
    addElement({
      type: 'drawing',
      position: position || getTargetPosition(),
      width: 400,
      height: 300,
      rotation: 0,
      src: '',
    });
  }, [addElement, getTargetPosition]);

  // --- Layout Functions ---
  const getSelectedElementsBBox = () => {
    const selected = elements.filter(el => selectedElementIds.includes(el.id));
    if (selected.length === 0) return null;
    const minX = Math.min(...selected.map(el => el.position.x - el.width / 2));
    const maxX = Math.max(...selected.map(el => el.position.x + el.width / 2));
    const minY = Math.min(...selected.map(el => el.position.y - el.height / 2));
    const maxY = Math.max(...selected.map(el => el.position.y + el.height / 2));
    return { minX, maxX, minY, maxY, centerX: (minX + maxX) / 2, centerY: (minY + maxY) / 2 };
  };

  const alignElements = (type: 'left' | 'center' | 'right' | 'top' | 'middle' | 'bottom') => {
    const bbox = getSelectedElementsBBox();
    if (!bbox) return;
    setElements(prev => prev.map(el => {
      if (!selectedElementIds.includes(el.id)) return el;
      let newPos = { ...el.position };
      if (type === 'left') newPos.x = bbox.minX + el.width / 2;
      if (type === 'center') newPos.x = bbox.centerX;
      if (type === 'right') newPos.x = bbox.maxX - el.width / 2;
      if (type === 'top') newPos.y = bbox.minY + el.height / 2;
      if (type === 'middle') newPos.y = bbox.centerY;
      if (type === 'bottom') newPos.y = bbox.maxY - el.height / 2;
      return { ...el, position: newPos };
    }));
  };

  const distributeElements = (direction: 'h' | 'v') => {
    const selected = elements.filter(el => selectedElementIds.includes(el.id));
    if (selected.length < 3) return;
    const sorted = [...selected].sort((a, b) => direction === 'h' ? a.position.x - b.position.x : a.position.y - b.position.y);
    const first = sorted[0];
    const last = sorted[sorted.length - 1];
    const totalDist = direction === 'h' ? last.position.x - first.position.x : last.position.y - first.position.y;
    const step = totalDist / (sorted.length - 1);

    setElements(prev => prev.map(el => {
      const idx = sorted.findIndex(s => s.id === el.id);
      if (idx === -1) return el;
      let newPos = { ...el.position };
      if (direction === 'h') newPos.x = first.position.x + idx * step;
      else newPos.y = first.position.y + idx * step;
      return { ...el, position: newPos };
    }));
  };

  const tidyUp = () => {
    const selected = elements.filter(el => selectedElementIds.includes(el.id));
    const list = selected.length > 0 ? selected : elements;
    if (list.length === 0) return;

    const sorted = [...list].sort((a, b) => (a.position.y - b.position.y) || (a.position.x - b.position.x));
    const startX = Math.min(...list.map(el => el.position.x));
    const startY = Math.min(...list.map(el => el.position.y));
    const cols = Math.ceil(Math.sqrt(list.length));
    const spacing = 40;

    let maxWidth = Math.max(...list.map(el => el.width));
    let maxHeight = Math.max(...list.map(el => el.height));

    setElements(prev => prev.map(el => {
      const idx = sorted.findIndex(s => s.id === el.id);
      if (idx === -1) return el;
      const row = Math.floor(idx / cols);
      const col = idx % cols;
      return {
        ...el,
        rotation: 0,
        position: {
          x: startX + col * (maxWidth + spacing) + el.width / 2,
          y: startY + row * (maxHeight + spacing) + el.height / 2
        }
      };
    }));
  };

  // --- Core Handlers ---
  const updateElements = useCallback((updatedElement: CanvasElement, dragDelta?: Point) => {
    setElements(prevElements => {
      const selectedSet = new Set(selectedElementIds);
      return prevElements.map(el => {
        if (el.id === updatedElement.id || (dragDelta && selectedSet.has(el.id))) {
          let target = el.id === updatedElement.id ? updatedElement : { ...el, position: { x: el.position.x + dragDelta!.x, y: el.position.y + dragDelta!.y } };
          if (isSnapEnabled && dragDelta) {
            target.position.x = Math.round(target.position.x / GRID_SIZE) * GRID_SIZE;
            target.position.y = Math.round(target.position.y / GRID_SIZE) * GRID_SIZE;
            target.rotation = Math.round(target.rotation / 15) * 15;
          }
          return target;
        }
        return el;
      });
    }, { addToHistory: false });
  }, [selectedElementIds, setElements, isSnapEnabled]);

  const handlePasteFromClipboard = useCallback(async () => {
    try {
        const clipboardItems = await navigator.clipboard.read();
        for (const item of clipboardItems) {
            const imageType = item.types.find(type => type.startsWith('image/'));
            if (imageType) {
                const blob = await item.getType(imageType);
                const reader = new FileReader();
                reader.onload = (e) => {
                    const src = e.target?.result as string;
                    if (src) {
                        const img = new Image();
                        img.onload = () => {
                            addElement({ type: 'image', position: getTargetPosition(), src, width: Math.min(img.width, 400), height: Math.min(img.height, 400), rotation: 0 });
                        };
                        img.src = src;
                    }
                };
                reader.readAsDataURL(blob);
                return;
            }
            if (item.types.includes('text/plain')) {
                const blob = await item.getType('text/plain');
                const text = await blob.text();
                if (text) {
                    try {
                        const data = JSON.parse(text);
                        if (Array.isArray(data)) {
                             setElements(prev => [...prev, ...data.map(d => ({...d, id: `${Date.now()}-${Math.random()}`, zIndex: zIndexCounter.current++ }))]);
                             return;
                        }
                    } catch(e) {}
                    addNote(getTargetPosition());
                }
            }
        }
    } catch (err) {}
  }, [addElement, getTargetPosition, setElements, addNote]);

  const handleCopySelection = async () => {
    const selected = elements.filter(el => selectedElementIds.includes(el.id));
    if (selected.length === 0) return;
    if (selected.length === 1 && (selected[0].type === 'image' || selected[0].type === 'drawing')) {
        const response = await fetch(selected[0].src);
        const blob = await response.blob();
        await navigator.clipboard.write([new ClipboardItem({ [blob.type]: blob })]);
    } else {
        await navigator.clipboard.writeText(JSON.stringify(selected));
    }
  };

  const handleExportCanvas = () => {
    const dataStr = JSON.stringify(elements, null, 2);
    // Disambiguate global Blob from any potential conflict with @google/genai's Blob interface
    // Note: line 449 in user's reported error might correspond to this area depending on file padding/imports.
    const blob = new window.Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `canvas-${Date.now()}.json`;
    link.click();
  };

  const handleImportCanvas = (e: any) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
        try {
            const data = JSON.parse(event.target?.result as string);
            setElements(data);
        } catch(e) { alert("Invalid JSON"); }
    };
    reader.readAsText(file);
  };

  return (
    <main className="relative w-screen h-screen bg-gray-100 font-sans">
      <div 
        className={`absolute top-4 z-20 p-4 bg-white/95 backdrop-blur-md rounded-xl shadow-2xl border border-gray-200 w-72 flex flex-col gap-4 transition-all duration-300 ${isMenuCollapsed ? (panelAlignment === 'left' ? '-translate-x-full' : 'translate-x-full') : 'translate-x-0'} ${panelAlignment === 'left' ? 'left-4' : 'right-4'}`}
      >
        <div className="flex justify-between items-center">
          <h1 className="text-xl font-black text-blue-600 flex items-center gap-1">
              <span className="text-2xl">🍌</span> {t('infiniteCanvas')}
          </h1>
          <button onClick={() => setLanguage(l => l === 'zh' ? 'en' : 'zh')} className="text-xs font-bold text-gray-500 hover:text-blue-600 transition-colors uppercase tracking-widest">{language}</button>
        </div>

        <div className="grid grid-cols-2 gap-2">
            <button onClick={() => addNote()} className="px-3 py-2 text-xs font-bold bg-blue-600 text-white rounded-lg hover:bg-blue-700 shadow-sm flex flex-col items-center gap-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                {t('addNote')}
            </button>
            <button onClick={() => addArrow()} className="px-3 py-2 text-xs font-bold bg-green-600 text-white rounded-lg hover:bg-green-700 shadow-sm flex flex-col items-center gap-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 8l4 4m0 0l-4 4m4-4H3"/></svg>
                {t('addArrow')}
            </button>
            <button onClick={() => addDrawing()} className="px-3 py-2 text-xs font-bold bg-purple-600 text-white rounded-lg hover:bg-purple-700 shadow-sm flex flex-col items-center gap-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"/></svg>
                {t('addDrawing')}
            </button>
            <label className="cursor-pointer px-3 py-2 text-xs font-bold bg-orange-500 text-white rounded-lg hover:bg-orange-600 shadow-sm flex flex-col items-center gap-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"/></svg>
                {t('addImages')}
                <input type="file" accept="image/*" className="hidden" onChange={(e) => {
                    const files = Array.from(e.target.files || []);
                    if(files.length > 0) {
                        const reader = new FileReader();
                        reader.onload = (ev) => addElement({ type: 'image', position: getTargetPosition(), src: ev.target?.result, width: 300, height: 300, rotation: 0 });
                        reader.readAsDataURL(files[0]);
                    }
                }} />
            </label>
        </div>

        {/* Layout & Align Section */}
        <div className="border-t border-gray-100 pt-3 flex flex-col gap-2">
            <h2 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{t('layout')}</h2>
            <div className="flex items-center justify-between px-1">
              <span className="text-xs font-bold text-gray-600">{t('snapToGrid')}</span>
              <button 
                onClick={() => setIsSnapEnabled(!isSnapEnabled)}
                className={`w-10 h-5 rounded-full transition-colors relative ${isSnapEnabled ? 'bg-blue-500' : 'bg-gray-300'}`}
              >
                <div className={`absolute top-1 left-1 w-3 h-3 bg-white rounded-full transition-transform ${isSnapEnabled ? 'translate-x-5' : 'translate-x-0'}`} />
              </button>
            </div>
            <div className="grid grid-cols-3 gap-1">
                <button onClick={() => alignElements('left')} className="p-2 bg-gray-50 rounded hover:bg-gray-100" title={t('alignLeft')}><svg className="w-4 h-4 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M4 19h2V5H4v14zm5-4h9v-2H9v2zm0-5h11V8H9v2z"/></svg></button>
                <button onClick={() => alignElements('center')} className="p-2 bg-gray-50 rounded hover:bg-gray-100" title={t('alignCenter')}><svg className="w-4 h-4 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M8 19h3v2h2v-2h3v-2h-3v-2h-2v2H8v2zm-2-7h12v-2H6v2zm3-5h6V5H9v2z"/></svg></button>
                <button onClick={() => alignElements('right')} className="p-2 bg-gray-50 rounded hover:bg-gray-100" title={t('alignRight')}><svg className="w-4 h-4 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M18 19h2V5h-2v14zM6 15h9v-2H6v2zm0-5h11V8H6v2z"/></svg></button>
                <button onClick={() => alignElements('top')} className="p-2 bg-gray-50 rounded hover:bg-gray-100" title={t('alignTop')}><svg className="w-4 h-4 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M5 4v2h14V4H5zm10 5v9h-2V9h2zm-5 0v11H8V9h2z"/></svg></button>
                <button onClick={() => alignElements('middle')} className="p-2 bg-gray-50 rounded hover:bg-gray-100" title={t('alignMiddle')}><svg className="w-4 h-4 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M19 8v3h2v2h-2v3h-2v-3h-2v-2h2V8h2zm-7-2v12h-2V6h2zm-5 3v6H5V9h2z"/></svg></button>
                <button onClick={() => alignElements('bottom')} className="p-2 bg-gray-50 rounded hover:bg-gray-100" title={t('alignBottom')}><svg className="w-4 h-4 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M5 18v2h14v-2H5zm10-5v-9h-2v9h2zm-5-0v-11H8v11h2z"/></svg></button>
                <button onClick={() => distributeElements('h')} className="p-2 bg-gray-50 rounded hover:bg-gray-100" title={t('distributeH')}><svg className="w-4 h-4 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M4 5v14h2V5H4zm14 0v14h2V5h-2zM8 8h8v2H8V8zm0 6h8v2H8v-2z"/></svg></button>
                <button onClick={() => distributeElements('v')} className="p-2 bg-gray-50 rounded hover:bg-gray-100" title={t('distributeV')}><svg className="w-4 h-4 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M5 4h14v2H5V4zm0 14h14v2H5v-2zM8 8v8h2V8H8zm6 0v8h2V8h-2z"/></svg></button>
                <button onClick={tidyUp} className="p-2 bg-blue-50 text-blue-600 rounded hover:bg-blue-100 font-bold text-[10px] flex items-center justify-center gap-1" title={t('tidyUp')}>
                  <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 24 24"><path d="M3 3h8v8H3V3zm10 0h8v8h-8V3zM3 13h8v8H3v-8zm10 0h8v8h-8v-8z"/></svg>
                  {t('tidyUp')}
                </button>
            </div>
        </div>

        <div className="border-t border-gray-100 pt-3 flex flex-col gap-2">
            <div className="grid grid-cols-2 gap-2">
                <button onClick={handleCopySelection} className="px-2 py-2 text-xs font-bold bg-gray-50 text-gray-700 rounded-lg hover:bg-gray-100">{t('copyToClipboard')}</button>
                <button onClick={handlePasteFromClipboard} className="px-2 py-2 text-xs font-bold bg-gray-50 text-gray-700 rounded-lg hover:bg-gray-100">{t('pasteFromClipboard')}</button>
                <button onClick={handleExportCanvas} className="px-2 py-2 text-xs font-bold bg-blue-50 text-blue-700 rounded-lg hover:bg-blue-100">{t('export')}</button>
                <label className="cursor-pointer text-center px-2 py-2 text-xs font-bold bg-blue-50 text-blue-700 rounded-lg hover:bg-blue-100">
                    {t('import')}
                    <input type="file" accept=".json" className="hidden" onChange={handleImportCanvas} />
                </label>
            </div>
            <div className="grid grid-cols-2 gap-2">
                <button onClick={undo} disabled={!canUndo} className="px-2 py-2 text-xs font-bold bg-gray-100 text-gray-500 rounded-lg disabled:opacity-30">{t('undo')}</button>
                <button onClick={redo} disabled={!canRedo} className="px-2 py-2 text-xs font-bold bg-gray-100 text-gray-500 rounded-lg disabled:opacity-30">{t('redo')}</button>
                <button onClick={() => setResetView(() => resetView)} className="px-2 py-2 text-xs font-bold bg-gray-200 text-gray-700 rounded-lg col-span-2">{t('resetView')}</button>
            </div>
        </div>
      </div>

      <button
        onClick={() => setIsMenuCollapsed(!isMenuCollapsed)}
        className={`absolute top-4 z-20 p-2.5 bg-white rounded-full shadow-xl border border-gray-200 hover:bg-gray-50 transition-all ${panelAlignment === 'left' ? 'left-4' : 'right-4'}`}
        style={{ transform: isMenuCollapsed ? 'none' : (panelAlignment === 'left' ? 'translateX(288px)' : 'translateX(-288px)') }}
      >
        <svg xmlns="http://www.w3.org/2000/svg" className={`h-5 w-5 text-gray-600 transition-transform ${isMenuCollapsed ? '' : 'rotate-180'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7" />
        </svg>
      </button>

      <InfiniteCanvas 
        ref={canvasApiRef}
        elements={elements} 
        selectedElementIds={selectedElementIds}
        onSelectElement={setSelectedElementIds as any}
        onMarqueeSelect={setSelectedElementIds as any}
        onUpdateElement={updateElements as any}
        onUpdateMultipleElements={(updates) => setElements(prev => prev.map(el => {
          const update = updates.find(u => u.id === el.id);
          return update ? { ...el, ...update } : el;
        })) as any}
        onInteractionEnd={() => {}}
        setResetViewCallback={setResetView} 
        onGenerate={() => {}}
        onContextMenu={(e, world, id) => setContextMenu({ x: (e as any).clientX, y: (e as any).clientY, worldPoint: world, elementId: id })}
        onEditDrawing={setEditingDrawing as any}
        onMouseMove={() => {}}
        onViewportChange={setViewport}
        imageStyle={imageStyle}
        onSetImageStyle={setImageStyle}
        imageAspectRatio={imageAspectRatio}
        onSetImageAspectRatio={setImageAspectRatio}
        outpaintingState={outpaintingState}
        onUpdateOutpaintingFrame={() => {}}
        onCancelOutpainting={() => setOutpaintingState(null)}
        onOutpaintingGenerate={() => {}}
        onAutoPromptGenerate={async () => ""}
        interactionMode={interactionMode}
        t={t}
        language={language}
        analysisResults={analysisResults}
        analyzingElementId={analyzingElementId}
        onAnalyzeElement={() => {}}
        onOptimizeNotePrompt={() => {}}
        analysisVisibility={analysisVisibility}
        onToggleAnalysisVisibility={() => {}}
        onClearAnalysis={() => {}}
        onTranslateAnalysis={() => {}}
        translatingElementId={translatingElementId}
      />

      <Minimap elements={elements} viewport={viewport} onPanTo={(p) => canvasApiRef.current?.panTo(p)} onZoomIn={() => canvasApiRef.current?.zoomIn()} onZoomOut={() => canvasApiRef.current?.zoomOut()} />

      {contextMenu && (
        <ContextMenu
          menuData={contextMenu}
          onClose={() => setContextMenu(null)}
          actions={{
            addNote, addArrow, addDrawing, editDrawing: setEditingDrawing as any,
            startImageEdit: setEditingImage as any, startOutpainting: () => {},
            addImage: () => imageInputRef.current?.click(), deleteElement: () => setElements(prev => prev.filter(el => !selectedElementIds.includes(el.id))), bringToFront: () => {}, sendToBack: () => {},
            changeColor: (color) => setElements(prev => prev.map(el => selectedElementIds.includes(el.id) ? {...el, color} : el)), downloadImage: () => {}, duplicateElement: () => {},
            toggleLanguage: () => setLanguage(l => l === 'zh' ? 'en' : 'zh'), groupElements: () => {}, ungroupElements: () => {}, copyToClipboard: () => {}
          }}
          canChangeColor={true}
          canGroup={false}
          canUngroup={false}
          elementType={null}
          t={t}
        />
      )}
    </main>
  );
};

export default App;
